#!/usr/bin/env python3
import argparse
import json
import math
import os
import shutil
import stat
import struct
import sys
from dataclasses import dataclass
from pathlib import Path

MAX_ENTRIES_PER_DIRECTORY = 30
MAX_SHARD_SIZE = 15_000_000
MAGIC = b"RSHARD1\n"
FORMAT_NAME = "openhands-reshard-v1"
DATA_DIR_NAME = "__reshard_data__"
MANIFEST_NAME = "__reshard_manifest__.json"
SHARD_SUFFIX = ".rshard"

TYPE_DIR = ord("D")
TYPE_FILE = ord("F")
TYPE_SYMLINK = ord("L")

DIR_HEADER = struct.Struct(">BIIq")
FILE_HEADER = struct.Struct(">BIIqQQQ")
SYMLINK_HEADER = struct.Struct(">BIIqI")


@dataclass(frozen=True)
class DirectoryRecord:
    path: str
    path_bytes: bytes
    mode: int
    mtime_ns: int


@dataclass(frozen=True)
class FileRecord:
    path: Path
    rel_path: str
    path_bytes: bytes
    mode: int
    mtime_ns: int
    size: int


@dataclass(frozen=True)
class SymlinkRecord:
    path: str
    path_bytes: bytes
    target_bytes: bytes
    mode: int
    mtime_ns: int


def positive_capacity() -> int:
    return MAX_SHARD_SIZE - len(MAGIC)


def encoded_relative_path(root: Path, path: Path) -> tuple[str, bytes]:
    rel = path.relative_to(root).as_posix()
    if not rel or rel == "." or rel.startswith("../") or rel.startswith("/"):
        raise ValueError(f"Unsafe relative path generated for {path}")
    return rel, os.fsencode(rel)


def collect_records(input_dir: Path) -> list[object]:
    records: list[object] = []

    def walk(directory: Path) -> None:
        with os.scandir(directory) as iterator:
            entries = sorted(iterator, key=lambda entry: entry.name)
        for entry in entries:
            path = Path(entry.path)
            st = entry.stat(follow_symlinks=False)
            mode = stat.S_IMODE(st.st_mode)
            rel, rel_bytes = encoded_relative_path(input_dir, path)

            if entry.is_symlink():
                target = os.readlink(path)
                records.append(
                    SymlinkRecord(
                        path=rel,
                        path_bytes=rel_bytes,
                        target_bytes=os.fsencode(target),
                        mode=mode,
                        mtime_ns=st.st_mtime_ns,
                    )
                )
            elif entry.is_dir(follow_symlinks=False):
                records.append(
                    DirectoryRecord(
                        path=rel,
                        path_bytes=rel_bytes,
                        mode=mode,
                        mtime_ns=st.st_mtime_ns,
                    )
                )
                walk(path)
            elif entry.is_file(follow_symlinks=False):
                records.append(
                    FileRecord(
                        path=path,
                        rel_path=rel,
                        path_bytes=rel_bytes,
                        mode=mode,
                        mtime_ns=st.st_mtime_ns,
                        size=st.st_size,
                    )
                )
            else:
                raise ValueError(f"Unsupported filesystem entry: {path}")

    walk(input_dir)
    return records


def require_record_fits(record_size_without_magic: int, path: str) -> None:
    if record_size_without_magic > positive_capacity():
        raise ValueError(
            f"Metadata for {path!r} is too large to fit in a {MAX_SHARD_SIZE} byte shard"
        )


def simulate_shard_count(records: list[object]) -> int:
    shard_count = 0
    current_size = 0

    def ensure_open() -> None:
        nonlocal shard_count, current_size
        if shard_count == 0 or current_size == 0:
            shard_count += 1
            current_size = len(MAGIC)

    def add_record(record_size: int, path: str) -> None:
        nonlocal shard_count, current_size
        require_record_fits(record_size, path)
        ensure_open()
        if current_size + record_size > MAX_SHARD_SIZE:
            shard_count += 1
            current_size = len(MAGIC)
        current_size += record_size

    for record in records:
        if isinstance(record, DirectoryRecord):
            add_record(DIR_HEADER.size + len(record.path_bytes), record.path)
        elif isinstance(record, SymlinkRecord):
            add_record(
                SYMLINK_HEADER.size + len(record.path_bytes) + len(record.target_bytes),
                record.path,
            )
        elif isinstance(record, FileRecord):
            overhead = FILE_HEADER.size + len(record.path_bytes)
            require_record_fits(overhead, record.rel_path)
            ensure_open()
            if record.size == 0:
                add_record(overhead, record.rel_path)
                continue

            remaining = record.size
            while remaining > 0:
                ensure_open()
                if current_size + overhead > MAX_SHARD_SIZE:
                    shard_count += 1
                    current_size = len(MAGIC)
                available = MAX_SHARD_SIZE - current_size - overhead
                if available <= 0:
                    shard_count += 1
                    current_size = len(MAGIC)
                    available = MAX_SHARD_SIZE - current_size - overhead
                chunk_size = min(remaining, available)
                current_size += overhead + chunk_size
                remaining -= chunk_size
        else:
            raise TypeError(f"Unexpected record type: {type(record)!r}")

    return shard_count


def directory_depth_for_shards(shard_count: int) -> int:
    if shard_count <= MAX_ENTRIES_PER_DIRECTORY:
        return 0
    leaf_count = math.ceil(shard_count / MAX_ENTRIES_PER_DIRECTORY)
    depth = 1
    capacity = MAX_ENTRIES_PER_DIRECTORY
    while leaf_count > capacity:
        depth += 1
        capacity *= MAX_ENTRIES_PER_DIRECTORY
    return depth


def shard_relative_path(shard_index: int, depth: int) -> Path:
    leaf_index, file_index = divmod(shard_index, MAX_ENTRIES_PER_DIRECTORY)
    parts: list[str] = []
    for power in range(depth - 1, -1, -1):
        digit = (leaf_index // (MAX_ENTRIES_PER_DIRECTORY**power)) % MAX_ENTRIES_PER_DIRECTORY
        parts.append(f"d{digit:02d}")
    return Path(*parts, f"shard-{shard_index:08d}{SHARD_SUFFIX}") if parts else Path(f"shard-{shard_index:08d}{SHARD_SUFFIX}")


class ShardWriter:
    def __init__(self, data_dir: Path, depth: int):
        self.data_dir = data_dir
        self.depth = depth
        self.shard_index = -1
        self.current_size = 0
        self.current_file = None

    def close(self) -> None:
        if self.current_file is not None:
            self.current_file.close()
            self.current_file = None

    @property
    def shard_count(self) -> int:
        return self.shard_index + 1

    def open_next_shard(self) -> None:
        self.close()
        self.shard_index += 1
        path = self.data_dir / shard_relative_path(self.shard_index, self.depth)
        path.parent.mkdir(parents=True, exist_ok=True)
        self.current_file = path.open("wb")
        self.current_file.write(MAGIC)
        self.current_size = len(MAGIC)

    def ensure_space(self, record_size: int, path: str) -> None:
        require_record_fits(record_size, path)
        if self.current_file is None:
            self.open_next_shard()
        if self.current_size + record_size > MAX_SHARD_SIZE:
            self.open_next_shard()

    def write_bytes_record(self, payload: bytes, path: str) -> None:
        self.ensure_space(len(payload), path)
        assert self.current_file is not None
        self.current_file.write(payload)
        self.current_size += len(payload)

    def write_directory(self, record: DirectoryRecord) -> None:
        payload = DIR_HEADER.pack(TYPE_DIR, len(record.path_bytes), record.mode, record.mtime_ns)
        payload += record.path_bytes
        self.write_bytes_record(payload, record.path)

    def write_symlink(self, record: SymlinkRecord) -> None:
        payload = SYMLINK_HEADER.pack(
            TYPE_SYMLINK,
            len(record.path_bytes),
            record.mode,
            record.mtime_ns,
            len(record.target_bytes),
        )
        payload += record.path_bytes + record.target_bytes
        self.write_bytes_record(payload, record.path)

    def write_file(self, record: FileRecord) -> None:
        overhead = FILE_HEADER.size + len(record.path_bytes)
        require_record_fits(overhead, record.rel_path)

        if record.size == 0:
            payload = FILE_HEADER.pack(
                TYPE_FILE,
                len(record.path_bytes),
                record.mode,
                record.mtime_ns,
                0,
                0,
                0,
            )
            payload += record.path_bytes
            self.write_bytes_record(payload, record.rel_path)
            return

        offset = 0
        with record.path.open("rb") as source:
            while offset < record.size:
                if self.current_file is None:
                    self.open_next_shard()
                if self.current_size + overhead > MAX_SHARD_SIZE:
                    self.open_next_shard()
                available = MAX_SHARD_SIZE - self.current_size - overhead
                if available <= 0:
                    self.open_next_shard()
                    available = MAX_SHARD_SIZE - self.current_size - overhead

                chunk_size = min(record.size - offset, available)
                chunk = source.read(chunk_size)
                if len(chunk) != chunk_size:
                    raise OSError(f"File changed while reading: {record.path}")

                header = FILE_HEADER.pack(
                    TYPE_FILE,
                    len(record.path_bytes),
                    record.mode,
                    record.mtime_ns,
                    record.size,
                    offset,
                    len(chunk),
                )
                assert self.current_file is not None
                self.current_file.write(header)
                self.current_file.write(record.path_bytes)
                self.current_file.write(chunk)
                self.current_size += overhead + len(chunk)
                offset += len(chunk)


def prepare_output_dir(input_dir: Path, output_dir: Path) -> None:
    input_resolved = input_dir.resolve()
    output_resolved = output_dir.resolve(strict=False)

    if output_resolved == input_resolved:
        raise ValueError("Output directory must be different from the input directory")
    if output_resolved.is_relative_to(input_resolved):
        raise ValueError("Output directory must not be inside the input directory")

    output_dir.mkdir(parents=True, exist_ok=True)
    if any(output_dir.iterdir()):
        raise ValueError(f"Output directory is not empty: {output_dir}")


def write_manifest(output_dir: Path, shard_count: int, depth: int) -> None:
    manifest = {
        "format": FORMAT_NAME,
        "data_dir": DATA_DIR_NAME,
        "max_entries_per_directory": MAX_ENTRIES_PER_DIRECTORY,
        "max_shard_size": MAX_SHARD_SIZE,
        "shard_count": shard_count,
        "directory_depth": depth,
    }
    payload = json.dumps(manifest, sort_keys=True, indent=2).encode("utf-8") + b"\n"
    if len(payload) > MAX_SHARD_SIZE:
        raise ValueError("Manifest exceeds maximum shard file size")
    (output_dir / MANIFEST_NAME).write_bytes(payload)


def validate_resharded_tree(output_dir: Path) -> None:
    for directory, dirnames, filenames in os.walk(output_dir):
        entry_count = len(dirnames) + len(filenames)
        if entry_count > MAX_ENTRIES_PER_DIRECTORY:
            raise RuntimeError(
                f"Directory {directory} contains {entry_count} entries, exceeding {MAX_ENTRIES_PER_DIRECTORY}"
            )
        for filename in filenames:
            path = Path(directory) / filename
            size = path.stat().st_size
            if size > MAX_SHARD_SIZE:
                raise RuntimeError(
                    f"File {path} is {size} bytes, exceeding {MAX_SHARD_SIZE}"
                )


def compress(input_dir: Path, output_dir: Path) -> None:
    if not input_dir.is_dir():
        raise ValueError(f"Input directory does not exist or is not a directory: {input_dir}")

    prepare_output_dir(input_dir, output_dir)
    records = collect_records(input_dir)
    expected_shards = simulate_shard_count(records)
    depth = directory_depth_for_shards(expected_shards)

    data_dir = output_dir / DATA_DIR_NAME
    data_dir.mkdir()
    writer = ShardWriter(data_dir, depth)
    try:
        for record in records:
            if isinstance(record, DirectoryRecord):
                writer.write_directory(record)
            elif isinstance(record, SymlinkRecord):
                writer.write_symlink(record)
            elif isinstance(record, FileRecord):
                writer.write_file(record)
            else:
                raise TypeError(f"Unexpected record type: {type(record)!r}")
    finally:
        writer.close()

    if writer.shard_count != expected_shards:
        raise RuntimeError(
            f"Internal shard count mismatch: simulated {expected_shards}, wrote {writer.shard_count}"
        )
    write_manifest(output_dir, writer.shard_count, depth)
    validate_resharded_tree(output_dir)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Reshard a directory into files no larger than 15MB and directories with at most 30 entries."
    )
    parser.add_argument("input_dir", type=Path)
    parser.add_argument("output_dir", type=Path)
    return parser.parse_args()


def main() -> int:
    args = parse_args()
    try:
        compress(args.input_dir, args.output_dir)
    except Exception as exc:
        print(f"compress.py: error: {exc}", file=sys.stderr)
        return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
import argparse
import json
import os
import shutil
import stat
import struct
import sys
import tempfile
from pathlib import Path, PurePosixPath

MAX_ENTRIES_PER_DIRECTORY = 30
MAX_SHARD_SIZE = 15_000_000
MAGIC = b"RSHARD1\n"
FORMAT_NAME = "openhands-reshard-v1"
DATA_DIR_NAME = "__reshard_data__"
MANIFEST_NAME = "__reshard_manifest__.json"
SHARD_SUFFIX = ".rshard"

TYPE_DIR = ord("D")
TYPE_FILE = ord("F")
TYPE_SYMLINK = ord("L")

DIR_HEADER = struct.Struct(">BIIq")
FILE_HEADER = struct.Struct(">BIIqQQQ")
SYMLINK_HEADER = struct.Struct(">BIIqI")


def read_exact(handle, size: int, context: str) -> bytes:
    data = handle.read(size)
    if len(data) != size:
        raise EOFError(f"Unexpected end of shard while reading {context}")
    return data


def destination_path(root: Path, path_bytes: bytes) -> Path:
    rel = os.fsdecode(path_bytes)
    pure = PurePosixPath(rel)
    if pure.is_absolute() or not pure.parts:
        raise ValueError(f"Unsafe stored path: {rel!r}")
    if any(part in ("", ".", "..") for part in pure.parts):
        raise ValueError(f"Unsafe stored path: {rel!r}")
    return root.joinpath(*pure.parts)


def apply_file_metadata(path: Path, mode: int, mtime_ns: int) -> None:
    os.chmod(path, mode)
    os.utime(path, ns=(mtime_ns, mtime_ns))


def apply_directory_metadata(directory_metadata: list[tuple[Path, int, int]]) -> None:
    for path, mode, mtime_ns in sorted(directory_metadata, key=lambda item: len(item[0].parts), reverse=True):
        os.chmod(path, mode)
        os.utime(path, ns=(mtime_ns, mtime_ns))


def read_manifest(root: Path) -> dict:
    manifest_path = root / MANIFEST_NAME
    if not manifest_path.is_file():
        raise ValueError(f"Missing reshard manifest: {manifest_path}")
    if manifest_path.stat().st_size > MAX_SHARD_SIZE:
        raise ValueError("Manifest exceeds maximum shard size")
    manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    if manifest.get("format") != FORMAT_NAME:
        raise ValueError("Unsupported or invalid reshard manifest format")
    if manifest.get("data_dir") != DATA_DIR_NAME:
        raise ValueError("Unsupported data directory in manifest")
    if manifest.get("max_entries_per_directory") != MAX_ENTRIES_PER_DIRECTORY:
        raise ValueError("Unsupported directory entry limit in manifest")
    if manifest.get("max_shard_size") != MAX_SHARD_SIZE:
        raise ValueError("Unsupported shard size in manifest")
    return manifest


def validate_compressed_root(root: Path, data_dir: Path) -> None:
    allowed = {MANIFEST_NAME, DATA_DIR_NAME}
    actual = {entry.name for entry in root.iterdir()}
    unexpected = actual - allowed
    if unexpected:
        raise ValueError(
            "Resharded directory contains unexpected entries; refusing to overwrite: "
            + ", ".join(sorted(unexpected))
        )
    if len(actual) > MAX_ENTRIES_PER_DIRECTORY:
        raise ValueError("Resharded root exceeds entry limit")
    if data_dir.exists() and not data_dir.is_dir():
        raise ValueError(f"Reshard data path is not a directory: {data_dir}")


def list_shards(data_dir: Path, expected_count: int) -> list[Path]:
    if expected_count == 0:
        if data_dir.exists() and any(data_dir.iterdir()):
            raise ValueError("Manifest says there are no shards, but shard data is present")
        return []
    if not data_dir.is_dir():
        raise ValueError(f"Missing shard data directory: {data_dir}")
    shards = sorted(path for path in data_dir.rglob(f"*{SHARD_SUFFIX}") if path.is_file())
    if len(shards) != expected_count:
        raise ValueError(f"Expected {expected_count} shards, found {len(shards)}")
    for shard in shards:
        size = shard.stat().st_size
        if size > MAX_SHARD_SIZE:
            raise ValueError(f"Shard exceeds maximum size: {shard}")
    return shards


def restore_shard(shard: Path, restore_root: Path, directory_metadata: list[tuple[Path, int, int]], file_metadata: dict[Path, tuple[int, int, int]]) -> None:
    with shard.open("rb") as handle:
        magic = read_exact(handle, len(MAGIC), str(shard))
        if magic != MAGIC:
            raise ValueError(f"Invalid shard magic: {shard}")

        while True:
            record_type_data = handle.read(1)
            if not record_type_data:
                break
            record_type = record_type_data[0]

            if record_type == TYPE_DIR:
                header_data = record_type_data + read_exact(handle, DIR_HEADER.size - 1, "directory header")
                _, path_len, mode, mtime_ns = DIR_HEADER.unpack(header_data)
                path = destination_path(restore_root, read_exact(handle, path_len, "directory path"))
                path.mkdir(parents=True, exist_ok=True)
                directory_metadata.append((path, mode, mtime_ns))
            elif record_type == TYPE_SYMLINK:
                header_data = record_type_data + read_exact(handle, SYMLINK_HEADER.size - 1, "symlink header")
                _, path_len, mode, mtime_ns, target_len = SYMLINK_HEADER.unpack(header_data)
                path = destination_path(restore_root, read_exact(handle, path_len, "symlink path"))
                target = os.fsdecode(read_exact(handle, target_len, "symlink target"))
                path.parent.mkdir(parents=True, exist_ok=True)
                if path.exists() or path.is_symlink():
                    path.unlink()
                os.symlink(target, path)
                try:
                    os.utime(path, ns=(mtime_ns, mtime_ns), follow_symlinks=False)
                except (NotImplementedError, OSError):
                    pass
            elif record_type == TYPE_FILE:
                header_data = record_type_data + read_exact(handle, FILE_HEADER.size - 1, "file header")
                _, path_len, mode, mtime_ns, total_size, offset, data_len = FILE_HEADER.unpack(header_data)
                path = destination_path(restore_root, read_exact(handle, path_len, "file path"))
                path.parent.mkdir(parents=True, exist_ok=True)

                if offset == 0:
                    with path.open("wb") as output:
                        shutil.copyfileobj(handle, output, length=data_len)
                else:
                    if not path.is_file():
                        raise ValueError(f"Missing prior chunk for {path}")
                    current_size = path.stat().st_size
                    if current_size != offset:
                        raise ValueError(
                            f"Out-of-order chunk for {path}: expected offset {current_size}, got {offset}"
                        )
                    with path.open("ab") as output:
                        shutil.copyfileobj(handle, output, length=data_len)

                actual_size = path.stat().st_size
                expected_size = offset + data_len
                if actual_size != expected_size:
                    raise ValueError(f"Failed to restore complete chunk for {path}")
                file_metadata[path] = (mode, mtime_ns, total_size)
            else:
                raise ValueError(f"Unknown record type {record_type} in {shard}")


def restore_to_temp(shards: list[Path], restore_root: Path) -> None:
    directory_metadata: list[tuple[Path, int, int]] = []
    file_metadata: dict[Path, tuple[int, int, int]] = {}

    for shard in shards:
        restore_shard(shard, restore_root, directory_metadata, file_metadata)

    for path, (mode, mtime_ns, total_size) in file_metadata.items():
        if path.stat().st_size != total_size:
            raise ValueError(f"Restored file has incorrect size: {path}")
        apply_file_metadata(path, mode, mtime_ns)
    apply_directory_metadata(directory_metadata)


def replace_with_restored_tree(root: Path, data_dir: Path, restore_root: Path) -> None:
    shutil.rmtree(data_dir)
    (root / MANIFEST_NAME).unlink()
    for item in sorted(restore_root.iterdir(), key=lambda path: path.name):
        shutil.move(str(item), str(root / item.name))
    restore_root.rmdir()


def decompress(root: Path) -> None:
    if not root.is_dir():
        raise ValueError(f"Resharded directory does not exist or is not a directory: {root}")

    manifest = read_manifest(root)
    data_dir = root / DATA_DIR_NAME
    validate_compressed_root(root, data_dir)
    shards = list_shards(data_dir, int(manifest["shard_count"]))

    restore_root = Path(
        tempfile.mkdtemp(prefix=f".{root.name}.restore.", dir=str(root.parent.resolve()))
    )
    try:
        restore_to_temp(shards, restore_root)
    except Exception:
        shutil.rmtree(restore_root, ignore_errors=True)
        raise

    validate_compressed_root(root, data_dir)
    replace_with_restored_tree(root, data_dir, restore_root)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Restore a directory created by compress.py in-place.")
    parser.add_argument("resharded_dir", type=Path)
    return parser.parse_args()


def main() -> int:
    args = parse_args()
    try:
        decompress(args.resharded_dir)
    except Exception as exc:
        print(f"decompress.py: error: {exc}", file=sys.stderr)
        return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

